1340:
SELECT SUM(CASE WHEN SUBSTR(T1.event_date, 1, 4) = '2019' THEN T2.spent ELSE 0 END) - SUM(CASE WHEN SUBSTR(T1.event_date, 1, 4) = '2020' THEN T2.spent ELSE 0 END) AS difference
FROM event AS T1
JOIN budget AS T2 ON T1.event_id = T2.link_to_event;

1148:
SELECT CAST(COUNT(*) AS REAL) * 100 / COUNT(id) AS percentage
FROM Player
WHERE height < 180 AND overall_rating > 70;

744:
SELECT COUNT(CASE WHEN T2.publisher_name = 'DC Comics' THEN 1 ELSE NULL END) - COUNT(CASE WHEN T2.publisher_name = 'Marvel Comics' THEN 1 ELSE NULL END) AS difference
FROM superhero AS T1
JOIN publisher AS T2 ON T1.publisher_id = T2.id;

685:
SELECT 
    (SELECT ViewCount FROM posts WHERE Title = 'Computer Game Datasets') AS TotalViews,
    (SELECT Top 1 LastEditorDisplayName FROM posts WHERE Title = 'Computer Game Datasets' ORDER BY CreationDate DESC) AS LastPoster;

352:
SELECT CAST(COUNT(CASE WHEN T2.language = 'Chinese Simplified' THEN T1.id ELSE NULL END) AS REAL) * 100 / COUNT(T1.id) AS percentage_chinese_simplified
FROM cards AS T1
JOIN foreign_data AS T2 ON T1.uuid = T2.uuid;

226:
SELECT ROUND(COUNT(CASE WHEN bond_type = '=' THEN 1 ELSE NULL END) * 100.0 / COUNT(bond_id), 5) AS percent
FROM bond
WHERE molecule_id = 'TR008';

47:
SELECT COUNT(*) / 12 AS MonthlyAverageOpenings
FROM schools
WHERE County = 'Alameda' AND DOC = 52 AND YEAR(OpenDate) = 1980;

92:
SELECT COUNT(district_id) AS num_districts
FROM district
WHERE A11 BETWEEN 6000 AND 10000;

94:
SELECT AVG(A11) AS avg_salary FROM client WHERE gender = 'F'
ORDER BY birth_date ASC LIMIT 1;

SELECT MAX(avg_salary) - MIN(avg_salary) AS salary_gap
FROM (
    SELECT AVG(A11) AS avg_salary
    FROM client
    WHERE gender = 'F'
    GROUP BY client_id
) AS avg_salaries;
